INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-0a2fc18c-moex-00093', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-34c7f7f6', 'sub-elementary-0a2fc18c-02', NULL, 'single_choice', '落日千林紫，漁舟聚淺灘。飛蓬雲外沒，野鳥望中還。寺小藏深樹，潮寬點亂山。一樽頻對 此，無意羨人間。（宋懋澄〈晚色〉） 根據上詩，下列敘述何者正確？', '["刻畫景物，藉景抒情", "蘊含瀟灑的出世之想", "充滿山水意趣，富有情韻", "描寫晚景，宛如一幅山水畫卷 近似「夕陽無限好，只是近黃昏」之意"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:13+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00094', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-34c7f7f6', 'sub-elementary-0a2fc18c-02', NULL, 'single_choice', '「畫家在素描時，勒定了所畫對象大約的輪廓後，只以炭筆磨擦出光影的陰暗與明亮，而不 做細部的描繪，保持一點朦朧感，以免整個畫面過於呆板。這個階段，就像詩一樣，在光與 暗、有與無之間，帶著一點迷濛，一點神祕，一點耐人追索的況味。然而這並非脫離現實， 仔細想想，我們在人生裡，大多數的情感都是這樣迷濛的吧！誰能肯定自己的內心無論是哪 一刻都清晰無比的呢？」 根據上文，下列選項正確的是：', '["擅長讀詩的人擁有最單純的心思，對世事經常感到懵懵懂懂", "詩在指涉、內涵上的模糊性，常能帶給讀者解釋探索的趣味", "詩與素描一樣，都不可進行細部描繪，才能提升整體的美感", "思緒清明的人難以享受讀詩之樂，因複雜處能輕易迎刃而解 生命中多數情感一如詩般迷濛，從詩中可以體會人生與現實"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:13+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00095', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-34c7f7f6', 'sub-elementary-0a2fc18c-02', NULL, 'single_choice', '「ChatGPT或Bing Chat多是提供定義式的短語，回覆的內容主要是『已知』的有限資訊， 難以『多義性』的語言表現感知複雜的人類思維。這是因為 AI 的訓練出自設計者目前的偏 好或定見，如果想讓AI更貼近人類需求，就必須仰賴人類持續更新且多樣化的經驗。」 根據上文，下列選項正確的是：', '["目前AI程式設計者偏好取樣多元的生活經驗", "AI現在仍未取代人類思想情感的複雜性表現", "AI設計者皆偏愛不受感知影響的科學性語言", "目前AI是以短語提供快速單一的資訊為目的 不斷轉型的語言文化和科技趨勢無直接關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:13+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00096', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列關於法源的敘述，何者錯誤？', '["憲法為國家的根本大法，規範政府組織及人民的權利義務", "法律經立法機關通過後，不待總統公布，即可發生效力", "命令係指行政機關基於法律授權或職權，所發布之規章，必須要注意不得超越母法的規定", "憲法、法律、命令等位階，憲法的位階最高，法律次之，命令最低"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:13+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00097', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '上級政府或主管機關，對於下級政府或機關所陳報之事項，加以審查，並作成決定，以完成該事項之法定 效力。上級政府或主管機關之行為，稱為：', '["考核", "備查", "監督", "核定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:13+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00098', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列有關擴張與限縮解釋的敘述，何者錯誤？', '["擴張解釋與限縮解釋，都是以文義的可能範圍為界限", "憲法第8條人民身體之自由應予保障，所稱人民指自然人，即為限縮解釋", "處罰或課予人民義務之規定文字，應從嚴解釋，不得任意擴張", "例外規定應為擴張解釋，否則有失其規定之旨"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:13+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00099', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列何者不是形成權？', '["甲、乙二人共有一筆土地，因協議分割不成，甲提起訴訟，請求法院為裁判分割", "甲售予車輛於乙，惟該車有瑕疵，乙向甲主張減少價金", "甲與乙成立買賣契約，甲未給付價金，15年後乙向甲請求給付價金，甲主張已超過15年，拒絕給付價金", "甲與乙成立買賣契約，但乙未於期限內給付，甲向乙解除契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:13+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00100', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '促進產業升級條例於民國99年5月12日公布廢止。關於該條例之廢止，下列敘述何者正確？', '["該條例之廢止，應經立法院通過，由立法院公布", "該條例之廢止，應經立法院通過，總統公布", "該條例之廢止，應由主管機關公布，並送立法院備查", "該條例於民國99年5月12日公布廢止時即失效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:13+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00101', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列何者為立法院通過，總統公布之法律？', '["財政部各地區國稅局組織通則", "內政部土地重劃工程處辦事細則", "工程施工查核小組組織準則", "不當黨產處理委員會組織規程"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:13+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00102', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '依司法院大法官解釋，關於法律保留原則，下列敘述何者正確？', '["對於人民生命之剝奪，應由憲法明文規範", "對於人民財產權之限制，僅能以法律為之", "對於人民入出境自由之限制，得由立法機關授權主管機關以命令限制之", "社會福利給付之資格、方式，皆非法律保留事項，行政機關得自行發布命令加以規範"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:13+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL)
